(196, 1, 'update', 'Property', 73, 'Updated property: 4 BR VILLA GAYA SANTORINI DEKAT PANTAI MELASTI – UNGASAN', '{\"old\":{\"id\":73,\"admin_id\":\"2\",\"views\":\"2\",\"property_number\":\"PN260100018\",\"title\":\"4 BR VILLA GAYA SANTORINI DEKAT PANTAI MELASTI \\u2013 UNGASAN\",\"slug\":\"4-br-santorini-style-villa-near-melasti-beach-ungasan\",\"description\":\"This Santorini-style villa is located on\\r\\nJalan Tukad Selatan\\r\\n, just\\r\\n3 km from Melasti Beach\\r\\nand\\r\\nneara mega project involving 4 foreign investment companies (PT PMA) developing a 4-hectare areain Ungasan\\r\\n. The surrounding neighborhood is peaceful, with a mix of local homes and villascurrently under construction.\\r\\nThis villa holds strong potential\\r\\nas an investment, considering theongoing development by both local and international investors in the area.\\r\\nThe average nightly\\r\\nrental rate for 4 bedrooms villas in this neighborhood ranges from IDR 3 to 4.5 million. Long-termrental opportunities are also available, with yearly rental prices between IDR 550\\u2013600 million.\",\"property_type\":\"villas\",\"property_status\":\"AVAILABLE\",\"pic_ref_number\":null,\"pic_name\":null,\"pic_email\":null,\"pic_whatsapp_number\":null,\"price\":\"5000000000.00\",\"price_monthly\":null,\"price_yearly\":null,\"price_freehold\":\"5000000000.00\",\"price_leasehold\":\"4550000000.00\",\"leasehold_period\":20,\"has_monthly\":false,\"has_yearly\":false,\"location_text\":\"Ungasan, Bali\",\"latitude\":null,\"longitude\":null,\"land_size\":\"165.00\",\"building_size\":\"300.00\",\"dimension\":\"10m x 16.5m\",\"direction\":\"West\",\"year_of_build\":null,\"floor_level\":\"3\",\"view\":null,\"style_design\":null,\"surrounding\":null,\"imb\":null,\"zone\":\"YELLOW\",\"living_room_type\":null,\"dining_room_type\":null,\"kitchen_type\":null,\"bedroom\":\"4\",\"bathroom\":\"5\",\"ensuite_bathroom\":null,\"extra_room\":null,\"storage\":null,\"swimming_pool\":true,\"terrace\":false,\"balcony\":false,\"shower\":false,\"furniture\":null,\"electricity_power\":null,\"ac_count\":null,\"water_source\":null,\"internet\":null,\"parking_type\":null,\"parking_size\":null,\"monthly_cost_included\":null,\"banjar_security\":false,\"cleaning_service\":false,\"pool_maintenance\":false,\"garden_maintenance\":false,\"bin_collection\":false,\"electricity_included\":false,\"internet_included\":false,\"advisor_notes\":\"Nearby Locations:\\r\\nMelasti Beach \\u2013 3 km (7 mins)\\r\\nWhite Rock Beach Club \\u2013 3 km (7 mins)\\r\\nGWK Gate Entrance \\u2013 5.7 km (12 mins)\\r\\nPandawa Beach \\u2013 6.3 km (15 mins)\",\"created_at\":\"2026-01-05T13:03:27.000000Z\",\"updated_at\":\"2026-01-07T08:39:33.000000Z\",\"is_featured\":false},\"new\":{\"title\":\"4 BR VILLA GAYA SANTORINI DEKAT PANTAI MELASTI \\u2013 UNGASAN\",\"description\":\"Villa bergaya Santorini ini terletak di Jalan Tukad Selatan dan berjarak 3 km dari Pantai Melasti, dekat dengan Mega Project 4 PT PMA yang membangun kawasan Ungasan seluas 4 hektar. Lingkungan sekitar terbilang tenang, banyak rumah lokal dan villa-villa yang sedang di bangun. Villa ini memiliki peluang potensial yang cukup tinggi mengingat area sekitar sedang di develop oleh investor dalam negeri dan luar negeri. Range harga sewa per malam untuk 4 bedroom di area sekitar di harga 3-4.5 juta atau bisa disewakan di tahunan di harga 550 - 600 juta.\",\"property_type\":\"villas\",\"property_status\":\"AVAILABLE\",\"pic_ref_number\":\"PPB12MAE\",\"pic_name\":\"Pemburu Property Bali\",\"pic_email\":\"pemburupropertybali@gmail.com\",\"pic_whatsapp_number\":\"+6281237741674\",\"price_monthly\":null,\"price_yearly\":null,\"price_freehold\":\"5000000000.00\",\"price_leasehold\":\"4550000000.00\",\"leasehold_period\":\"20\",\"location_text\":\"Ungasan, Bali\",\"latitude\":\"-8.83313970\",\"longitude\":\"115.15447010\",\"land_size\":\"165.00\",\"building_size\":\"300.00\",\"dimension\":\"10m x16.5m\",\"direction\":\"West\",\"year_of_build\":\"2023\",\"