(198, 1, 'update', 'Property', 75, 'Updated property: VILLA KOMERSIAL DEKAT SIDEWALK MALL – JIMBARAN', '{\"old\":{\"id\":75,\"admin_id\":\"2\",\"views\":\"2\",\"property_number\":\"PN260100020\",\"title\":\"2+1 BR VILLA KOMERSIAL DEKAT SIDEWALK MALL \\u2013 JIMBARAN\",\"slug\":\"21-br-commercial-villa-near-sidewalk-mall-jimbaran\",\"description\":\"This villa is located just a\\r\\nfew hundred meters from Sidewalk Mall Jimbaran and MovenpickResort.\\r\\nIts strategic location offers easy access\\r\\nto shopping malls, luxury resorts, local\\r\\nmarkets, schools, caf\\u00e9s, and restaurants. Built specifically for commercial purposes, the villahas been consistently rented out since it was completed, with a monthly rental rate of IDR 50\\u201360 million. Most tenants have been Russian foreigners. If you\\u2019re looking for a property thatgenerates passive income, this villa is a great option, all you have to do is continue theexisting rental operation.\",\"property_type\":\"commercials\",\"property_status\":\"AVAILABLE\",\"pic_ref_number\":null,\"pic_name\":null,\"pic_email\":null,\"pic_whatsapp_number\":null,\"price\":\"6000000000.00\",\"price_monthly\":null,\"price_yearly\":null,\"price_freehold\":\"6000000000.00\",\"price_leasehold\":null,\"leasehold_period\":null,\"has_monthly\":false,\"has_yearly\":false,\"location_text\":\"Jimbaran, Bali\",\"latitude\":null,\"longitude\":null,\"land_size\":\"200.00\",\"building_size\":\"200.00\",\"dimension\":\"10m x 20m\",\"direction\":\"South\",\"year_of_build\":null,\"floor_level\":\"2\",\"view\":null,\"style_design\":null,\"surrounding\":null,\"imb\":null,\"zone\":\"YELLOW\",\"living_room_type\":null,\"dining_room_type\":null,\"kitchen_type\":null,\"bedroom\":\"3\",\"bathroom\":\"3\",\"ensuite_bathroom\":null,\"extra_room\":null,\"storage\":null,\"swimming_pool\":true,\"terrace\":false,\"balcony\":true,\"shower\":false,\"furniture\":null,\"electricity_power\":null,\"ac_count\":null,\"water_source\":null,\"internet\":null,\