(199, 1, 'update', 'Property', 76, 'Updated property: 4 BR VILLA TERBESAR DI KOMPLEKS VILLA KOMERSIAL – UNGASAN', '{\"old\":{\"id\":76,\"admin_id\":\"2\",\"views\":\"2\",\"property_number\":\"PN260100021\",\"title\":\"4 BR VILLA TERBESAR DI KOMPLEKS VILLA KOMERSIAL \\u2013 UNGASAN\",\"slug\":\"4-br-the-largest-villa-in-a-commercial-villa-complex-ungasan\",\"description\":\"This villa is located on Jalan Mangelak, inside the Hideaway Residence Ungasan. An upscale,\\r\\nwell-maintained complex that enjoys a high occupancy rate of 75\\u201388%. The internal roads are 6\\r\\nmeters wide.\\r\\nThe villa is spread over two floors:\\r\\nGround Floor: main living area (living room, kitchen, dining area), service room, swimming pool,\\r\\nand a carport for two cars.\\r\\nSecond Floor: bedrooms, a balcony, and a family room.\\r\\nIn this complex, two-bedroom villas typically rent for IDR 2 \\u2013 3.5 million per night. With four\\r\\nbedrooms, this villa could be marketed at around IDR 3.5 \\u2013 5 million per night.\",\"property_type\":\"commercials\",\"property_status\":\"AVAILABLE\",\"pic_ref_number\":null,\"pic_name\":null,\"pic_email\":null,\"pic_whatsapp_number\":null,\"price\":\"7500000000.00\",\"price_monthly\":null,\"price_yearly\":null,\"price_freehold\":\"7500000000.00\",\"price_leasehold\":null,\"leasehold_period\":null,\"has_monthly\":false,\"has_yearly\":false,\"location_text\":\"Ungasan, Bali\",\"latitude\":null,\"longitude\":null,\"land_size\":\"405.00\",\"building_size\":\"436.00\",\"dimension\":\"18.4m x 22m\",\"direction\":null,\"year_of_build\":null,\"floor_level\":\"2\",\"view\":null,\"style_design\":null,\"surrounding\":null,\"imb\":null,\"zone\":\"YELLOW\",\"living_room_type\":null,\"dining_room_type\":null,\"kitchen_type\":null,\"bedroom\":\"4\",\"bathroom\":\"1\",\"ensuite_bathroom\":\"4\",\"extra_room\":null,\"storage\":null,\"swimming_pool\":true,\"terrace\":false,\"balcony\":false,\"shower\":false,\"furniture\":null,\"electricity_power\":null,\"a