(201, 1, 'update', 'Property', 75, 'Updated property: VILLA KOMERSIAL DEKAT SIDEWALK MALL – JIMBARAN', '{\"old\":{\"id\":75,\"admin_id\":\"2\",\"views\":\"2\",\"property_number\":\"PN260100020\",\"title\":\"VILLA KOMERSIAL DEKAT SIDEWALK MALL \\u2013 JIMBARAN\",\"slug\":\"21-br-commercial-villa-near-sidewalk-mall-jimbaran\",\"description\":\"Villa ini terletak beberapa ratus meter dari Mall Sidewalk Jimbaran atau Moven Pick Resort. Lokasinya cukup strategis karena dekat dengan mall, resort mewah, pasar, sekolah, dan cafe\\/restaurant. Villa ini dibangun untuk komersial sehingga sejak dibangun sampai sekarang selalu disewakan di harga 50-60 juta per bulan dan rata-rata penyewa adalah Foreigner Rusia. Jadi jika tujuan kamu adalah mencari passive income, villa ini sangat cocok karena kamu tinggal melanjutkan rental property ini.\",\"property_type\":\"villas\",\"property_status\":\"AVAILABLE\",\"pic_ref_number\":\"PPB12MAE\",\"pic_name\":\"Pemburu Property Bali\",\"pic_email\":\"pemburupropertybali@gmail.com\",\"pic_whatsapp_number\":\"+6281237741674\",\"price\":\"6000000000.00\",\"price_monthly\":null,\"price_yearly\":null,\"price_freehold\":\"6000000000.00\",\"price_leasehold\":null,\"leasehold_period\":null,\"has_monthly\":false,\"has_yearly\":false,\"location_text\":\"Jimbaran, Bali\",\"latitude\":\"-8.79328180\",\"longitude\":\"115.16228600\",\"land_size\":\"200.00\",\"building_size\":\"200.00\",\"dimension\":\"10m x 20m\",\"direction\":\"South\",\"year_of_build\":null,\"floor_level\":\"2\",\"view\":\"Residence\",\"style_design\":null,\"surrounding\":null,\"imb\":null,\"zone\":\"YELLOW\",\"living_room_type\":\"Close\",\"dining_room_type\":\"Close\",\"kitchen_type\":\"Close\",\"bedroom\":\"3\",\"bathroom\":\"3\",\"ensuite_bathroom\":null,\"extra_room\":\"2\",\"storage\":\"1\",\"swimming_pool\":true,\"terrace\":false,\"balcony\":true,\"shower\":false,\"furniture\":\"Fully furnished\",\"electricity_power\":\"7700\",\"ac_count\":\"3\",\"water_source\":\"PDAM\",\"intern