(245, 1, 'update', 'Property', 82, 'Updated property: VILLA MEWAH TERMURAH DI TOYANING - UNGASAN', '{\"old\":{\"id\":82,\"admin_id\":\"2\",\"views\":\"2\",\"property_number\":\"PN260100027\",\"title\":\"4 BR DIJUAL VILLA MEWAH TERMURAH DI KAWASAN WISATA BALI - UNGASAN\",\"slug\":\"4-br-sale-the-cheapest-luxury-villa-in-tourism-area-bali-ungasan\",\"description\":\"This villa is located on Jalan Toya Ning 1 and features two access roads. It is the only luxury\\r\\nvilla in the tourism zone being offered at such an affordable price. The location is in high\\r\\ndemand and offers a shortcut route that connects directly to the Pecatu area. Highly\\r\\nrecommended for those looking for a move-in-ready residence.\",\"property_type\":\"villas\",\"property_status\":\"AVAILABLE\",\"pic_ref_number\":null,\"pic_name\":null,\"pic_email\":null,\"pic_whatsapp_number\":null,\"price\":\"9000000000.00\",\"price_monthly\":null,\"price_yearly\":null,\"price_freehold\":\"9000000000.00\",\"price_leasehold\":null,\"leasehold_period\":null,\"has_monthly\":false,\"has_yearly\":false,\"location_text\":\"Ungasan, Bali\",\"latitude\":null,\"longitude\":null,\"land_size\":\"500.00\",\"building_size\":\"616.00\",\"dimension\":null,\"direction\":\"North\",\"year_of_build\":null,\"floor_level\":\"3\",\"view\":null,\"style_design\":null,\"surrounding\":null,\"imb\":null,\"zone\":\"YELLOW\",\"living_room_type\":null,\"dining_room_type\":null,\"kitchen_type\":null,\"bedroom\":\"4\",\"bathroom\":\"5\",\"ensuite_bathroom\":null,\"extra_room\":null,\"storage\":null,\"swimming_pool\":true,\"terrace\":false,\"balcony\":false,\"shower\":false,\"furniture\":null,\"electricity_power\":null,\"ac_count\":null,\"water_source\":null,\"internet\":null,\"parking_type\":null,\"parking_size\":null,\"monthly_cost_included\":null,\"banjar_security\":false,\"cleaning_service\":false,\"pool_maintenance\":false,\"garden_maintenance\":false,\"bin_collection\":false,\"electricity_included\":false,\"internet_included\":fal