(320, 1, 'update', 'Property', 83, 'Updated property: 3 BR VILLA MEWAH MEDITTERANIAN DENGAN PEMANDANGAN LAUT - UNGASAN', '{\"old\":{\"id\":83,\"admin_id\":\"2\",\"views\":\"2\",\"property_number\":\"PN260100028\",\"title\":\"3 BR VILLA MEWAH MEDITTERANIAN DENGAN PEMANDANGAN LAUT - UNGASAN\",\"slug\":\"3-br-luxury-villa-meditteranian-with-ocean-view-ungasan\",\"description\":\"This is a luxurious villa designed with a blend of Balinese and Mediterranean styles. Built during the\\r\\npandemic, the villa has served as a private retreat and has never been commercialized. It is\\r\\nstrategically located next to Garuda Wisnu Kencana (GWK) on the west side and Four Points Hotel\\r\\nUngasan on the east side. The villa faces south, offering an unobstructed ocean view at a relatively\\r\\nclose distance. If you wish to commercialize the property, several spaces can be converted into\\r\\nadditional bedrooms. Alternatively, the villa could be transformed into a restaurant or even a wedding\\r\\nchapel\\u2014taking full advantage of its stunning view.\",\"property_type\":\"villas\",\"property_status\":\"AVAILABLE\",\"pic_ref_number\":null,\"pic_name\":null,\"pic_email\":null,\"pic_whatsapp_number\":null,\"price\":\"10000000000.00\",\"price_monthly\":null,\"price_yearly\":null,\"price_freehold\":\"10000000000.00\",\"price_leasehold\":null,\"leasehold_period\":null,\"has_monthly\":false,\"has_yearly\":false,\"location_text\":\"Ungasan, Bali\",\"area\":null,\"latitude\":null,\"longitude\":null,\"land_size\":\"613.00\",\"building_size\":\"500.00\",\"dimension\":\"23.5m x 26m\",\"direction\":\"South\",\"year_of_build\":null,\"floor_level\":\"2\",\"view\":null,\"style_design\":null,\"surrounding\":null,\"imb\":null,\"zone\":\"YELLOW\",\"living_room_type\":null,\"dining_room_type\":null,\"kitchen_type\":null,\"bedroom\":\"3\",\"bathroom\":\"4\",\"ensuite_bathroom\":null,\"extra_room\":null,\"storage\":null,\"swimming_pool\":true,\"terrace\":false,\"balcony\":false,\"shower\":false,\"furniture\":null,\"electricity_power\":null,\"ac_count\":null,\"water_source\":null,\"internet\":null,\"parking_type\":null,\"parking_size\":null,\"monthly_cost_included\":null,\"banjar_security\":false,\"cleaning_service\":false,\"pool_maintenance\":false,\"garden_maintenance\":false,\"bin_collection\":false,\"electricity_included\":false,\"internet_included\":false,\"advisor_notes\":\"Nearby Locations:\\r\\nFour Points Hotel Ungasan \\u2013 550 m (2 minutes)\\r\\nGWK Gate Entrance \\u2013 700 m (3 minutes)\\r\\nSidewalk Mall Jimbaran \\u2013 1 km (6 minutes)\\r\\nPecatu Golf \\u2013 3 km (12 minutes)\\r\\nJimbaran Beach \\u2013 4 km (13 minutes)\\r\\nMelasti Beach \\u2013 5.3 km (15 minutes)\",\"created_at\":\"2026-01-06T12:30:28.000000Z\",\"updated_at\":\"2026-01-07T08:34:44.000000Z\",\"is_featured\":false,\"featured_order\":null},\"new\":{\"title\":\"3 BR VILLA MEWAH MEDITTERANIAN DENGAN PEMANDANGAN LAUT - UNGASAN\",\"description\":\"Villa ini merupakan villa mewah dengan nuasa bali - meditteranean. Dibangun pada masa pandemi, villa ini menjadi tempat persinggahan pribadi dan belum pernah dikomersilkan. \\r\\n\\r\\nLokasinya bersebelahan dengan GWK di sisi Barat dan bersebelahan dengan hotel Four Point Ungasan di sisi Timur. untuk hadapnya, villa ini menghadap Selatan, unblock ocean view dengan jarak pandang yang cukup dekat. Jika nantinya villa ini ingin dikomersilkan, beberapa space dapat dijadikan kamar tambahan. Atau bisa dialih fungsikan menjadi restaurant atau bahkan wedding chapel dengan pemandangan yang indah. \\r\\n\\r\\nLokasi dekat dengan : \\r\\nFour Point Hotel Ungasan - 550 m (2 menit)\\r\\nGWK Gate Entrance - 700 m (3 menit)\\r\\nSidewalk Mall Jimbaran - 1 km (6 menit)\\r\\nPecatu Golf - 3 km (12 menit)\\r\\nPantai Jimbaran - 4 km (13 menit)\\r\\nPantai Melasti - 5.3 km (15 menit)\",\"property_type\":\"villas\",\"property_status\":\"AVAILABLE\",\"pic_ref_number\":\"PPB12MAE\",\"pic_name\":\"Pemburu Property Bali\",\"pic_email\":\"pemburupropertybali@gmail.com\",\"pic_whatsapp_number\":\"+6281237741674\",\"price_monthly\":null,\"price_yearly\":null,\"price_freehold\":\"10000000000.00\",\"price_leasehold\":null,\"leasehold_period\":null,\"location_text\":\"Ungasan\",\"area\":null,\"latitude\":null,\"longitude\":null,\"land_size\":\"613.00\",\"building_size\":\"500.00\",\"dimension\":\"23.5m x 26m\",\"direction\":\"South\",\"year_of_build\":null,\"floor_level\":\"2\",\"view\":null,\"style_design\":null,\"surrounding\":null,\"imb\":null,\"zone\":\"YELLOW\",\"living_room_type\":null,\"dining_room_type\":null,\"kitchen_type\":null,\"bedroom\":\"3\",\"bathroom\":\"4\",\"ensuite_bathroom\":null,\"extra_room\":null,\"storage\":null,\"swimming_pool\":\"1\",\"furniture\":null,\"electricity_power\":null,\"ac_count\":null,\"water_source\":null,\"internet\":null,\"parking_type\":null,\"parking_size\":null,\"monthly_cost_included\":null,\"advisor_notes\":null,\"cover_photo_index\":null,\"tags\":[\"2\"],\"has_monthly\":false,\"has_yearly\":false,\"price\":\"10000000000.00\",\"terrace\":false,\"balcony\":false,\"shower\":false,\"banjar_security\":false,\"cleaning_service\":false,\"pool_maintenance\":false,\"garden_maintenance\":false,\"bin_collection\":false,\"electricity_included\":false,\"internet_included\":false}}', '182.253.51.60', 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/143.0.0.0 Safari/537.36', '2026-01-16 22:32:55', '2026-01-16 22:32:55'),
