(366, 1, 'update', 'Property', 56, 'Updated property: VILLA SANTORINI DEKAT PANTAI MELASTI - UNGASAN', '{\"old\":{\"id\":56,\"admin_id\":\"2\",\"views\":\"4\",\"property_number\":\"PN260100001\",\"title\":\"VILLA SANTORINI DEKAT PANTAI MELASTI - UNGASAN\",\"slug\":\"2-bedroom-santorini-villa-near-melasti-beach-ungasan\",\"description\":\"Villa bergaya Santorini ini terletak di Jalan Tukad Selatan dan berjarak 3 km dari Pantai Melasti, dekat dengan Mega Project 4 PT PMA yang membangun kawasan Ungasan seluas 4 hektar. Lingkungan sekitar terbilang tenang, banyak rumah lokal dan villa-villa yang sedang di bangun. Villa ini memiliki peluang potensial yang cukup tinggi mengingat area sekitar sedang di develop oleh investor dalam negeri dan luar negeri. Range harga sewa per malam sekitar 1.8 -2.5 juta.\",\"property_type\":\"villas\",\"property_status\":\"AVAILABLE\",\"pic_ref_number\":\"PPB12MAE\",\"pic_name\":\"Pemburu Property Bali\",\"pic_email\":\"pemburupropertybali@gmail.com\",\"pic_whatsapp_number\":\"+6281237741674\",\"price\":\"1900000000.00\",\"price_monthly\":null,\"price_yearly\":null,\"price_freehold\":\"1900000000.00\",\"price_leasehold\":null,\"leasehold_period\":null,\"has_monthly\":false,\"has_yearly\":false,\"location_text\":\"Jalan Tukad Selatan, Bali\",\"area\":null,\"latitude\":\"-8.83314500\",\"longitude\":\"115.15704500\",\"land_size\":\"130.00\",\"building_size\":\"150.00\",\"dimension\":\"10m x 13m\",\"direction\":\"West\",\"year_of_build\":\"2024\",\"floor_level\":\"1\",\"view\":\"Residence\",\"style_design\":\"Santorini\",\"surrounding\":null,\"imb\":null,\"zone\":\"YELLOW\",\"living_room_type\":\"Open\",\"dining_room_type\":\"Open\",\"kitchen_type\":\"Open\",\"bedroom\":\"2\",\"bathroom\":\"3\",\"ensuite_bathroom\":null,\"extra_room\":null,\"storage\":\"0\",\"swimming_pool\":false,\"terrace\":false,\"balcony\":false,\"shower\":false,\"furniture\":\"Semi furnished\",\"electricity_power\":\"5500\",\"ac_count\":null,\"water_source\":\"PDAM\",\"inte