(436, 1, 'update', 'Property', 111, 'Updated property: VILLA KOMERSIAL DI JALAN TIYING TUYUL - PERERENAN', '{\"old\":{\"id\":111,\"admin_id\":\"2\",\"views\":\"0\",\"property_number\":\"PN260100055\",\"title\":\"VILLA KOMERSIAL DI JALAN TIYING TUYUL - PERERENAN\",\"slug\":\"villa-komersial-di-jalan-tiying-tuyul-pererenan\",\"description\":\"Villa komersil ini berjarak 100 meter dari Jalan Raya Tiyingtutul Pererenan. Sudah beroperasi di daily rental dengan harga 2,8 - 3,5 juta per malamnya sejak tahun 2022. Akses masuk villa ini 4-5 meter dengan lingkungan sekitar villa-villa komersil, restaurant dan store. Villa ini termasuk well designed dan well maintenance sehingga kamu gak perlu khawatir untuk melanjutkan rentalnya di harian atau bahkan tahunan dengan harga pasaran 3 bedroom di 500-600 juta per tahun karena lokasi yang sangat strategis dan reasonable.\\r\\n\\r\\nLokasi dekat dengan : \\r\\nRestaurant\\/Cafe\\/Store\\/Gym - 100 m (2 menit)\\r\\nJl Sempol - 500 m (5 menit)\\r\\nPantai Pererenan - 3.3 km (8 menit)\\r\\nPantai Batu Bolong Canggu - 4.1 km (13 menit)\",\"property_type\":\"commercials\",\"property_status\":\"AVAILABLE\",\"pic_ref_number\":\"PPB12MAE\",\"pic_name\":\"Pemburu Property Bali\",\"pic_email\":\"pemburupropertybali@gmail.com\",\"pic_whatsapp_number\":\"+6281237741674\",\"price\":\"5950000000.00\",\"price_monthly\":null,\"price_yearly\":null,\"price_freehold\":\"5950000000.00\",\"price_leasehold\":null,\"leasehold_period\":null,\"has_monthly\":false,\"has_yearly\":false,\"location_text\":\"Pererenan, Bali\",\"area\":null,\"latitude\":\"-8.67420180\",\"longitude\":\"115.12535570\",\"land_size\":\"170.00\",\"building_size\":\"182.00\",\"dimension\":null,\"direction\":null,\"year_of_build\":null,\"floor_level\":\"2\",\"view\":null,\"style_design\":\"Modern Minimalis\",\"surrounding\":null,\"imb\":null,\"zone\":\"PINK\",\"living_room_type\":\"Open\",\"dining_room_type\":\"Open\",\"kitchen_type\":\"Open\",\"bedroom\":\"4\",\"bathroom\":\"4\",\"ensu