(662, 2, 'update', 'Property', 164, 'Updated property: VILLA UNFURNISHED MODERN DI MUNGGU CEPAKA', '{\"old\":{\"id\":164,\"admin_id\":\"2\",\"views\":\"12\",\"property_number\":\"PN260200009\",\"transaction_number\":\"00003\",\"title\":\"VILLA UNFURNISHED MODERN DI MUNGGU CEPAKA\",\"slug\":\"villa-unfurnished-modern-di-munggu-cepaka\",\"description\":\"Villa cantik 2 kamar tidur dengan pemandangan sawah dan laut. \\r\\n\\ud83d\\udcdc Leasehold 22 tahun (opsi perpanjangan)\\r\\n\\ud83d\\udcd1 SLF \\/ PBG dalam proses\\r\\n\\ud83c\\udfe1 Unfurnished\\r\\nPotensi sewa sangat bagus di lokasi yang sangat diminati.\",\"property_type\":\"villas\",\"property_type_id\":\"1\",\"property_status\":\"AVAILABLE\",\"expired_date\":\"2026-08-17T17:00:00.000000Z\",\"pic_ref_number\":\"AGPRD01\",\"pic_name\":\"Diana\",\"pic_email\":null,\"pic_whatsapp_number\":\"+6281388305558\",\"price\":\"3500000000.00\",\"price_monthly\":null,\"price_yearly\":null,\"price_freehold\":null,\"price_leasehold\":\"3500000000.00\",\"leasehold_period\":22,\"has_monthly\":false,\"has_yearly\":false,\"location_text\":\"Cepaka\",\"area\":\"Tabanan\",\"latitude\":\"-8.60660370\",\"longitude\":\"115.14606170\",\"land_size\":\"112.00\",\"building_size\":\"172.00\",\"dimension\":\"10m x 11m\",\"direction\":\"East\",\"year_of_build\":\"2026\",\"floor_level\":\"2\",\"view\":\"Rice fields\",\"style_design\":\"Modern Minimalist\",\"surrounding\":null,\"imb\":null,\"zone\":\"YELLOW\",\"living_room_type\":\"Open-Closed\",\"dining_room_type\":\"Open-Closed\",\"kitchen_type\":\"Open-Closed\",\"bedroom\":\"2\",\"bathroom\":\"1\",\"ensuite_bathroom\":\"2\",\"extra_room\":null,\"storage\":null,\"swimming_pool\":true,\"terrace\":false,\"balcony\":true,\"shower\":false,\"furniture\":\"Non Furnished\",\"electricity_power\":\"7700\",\"ac_count\":\"3\",\"water_source\":\"PDAM\",\"internet\":null,\"parking_type\":\"Private\",\"parking_size\":\"1 car + 2 motorcycle\",\"monthly_cost_included\":null,\"banjar_security\":false,\"cleaning_service\":false,\"pool_maintenance\":false,\"garden_maintenance\":false,\"bin_collection\":false,\"electricity_included\":false,\"internet_included\":false,\"advisor_notes\":null,\"created_at\":\"2026-02-19T08:47:28.000000Z\",\"updated_at\":\"2026-03-09T05:09:53.000000Z\",\"is_featured\":false,\"featured_order\":null},\"new\":{\"title\":\"VILLA UNFURNISHED MODERN DI MUNGGU CEPAKA\",\"description\":\"Set in a peaceful pocket of Munggu, this modern villa features expansive floor-to-ceiling windows that flood the interior with natural light and frame the surrounding landscape beautifully. From the bedroom and living areas, you enjoy uninterrupted rice field greenery with a glimpse of the ocean in the distance \\u2014 a view combination that is increasingly difficult to find this close to Canggu.\\r\\n\\r\\nWith 22 years leasehold remaining, this villa presents an attractive opportunity for investors looking to enter the Bali market in an emerging location. Munggu is gaining attention as a quieter alternative to nearby Canggu, yet still close to beach clubs, restaurants, and surfing beaches \\u2014 making it highly appealing for short-term rental guests.\",\"property_type_id\":\"1\",\"property_status\":\"AVAILABLE\",\"transaction_number\":\"00003\",\"validity_days\":null,\"pic_ref_number\":\"AGPRD01\",\"pic_name\":\"Diana\",\"pic_email\":null,\"pic_whatsapp_number\":\"+6281388305558\",\"price_monthly\":null,\"price_yearly\":null,\"price_freehold\":null,\"price_leasehold\":\"3500000000.00\",\"leasehold_period\":\"22\",\"location_text\":\"Cepaka\",\"area\":\"Tabanan\",\"latitude\":\"-8.60660370\",\"longitude\":\"115.14606170\",\"land_size\":\"112.00\",\"building_size\":\"172.00\",\"dimension\":\"10m x 11m\",\"direction\":\"East\",\"year_of_build\":\"2026\",\"floor_level\":\"2\",\"view\":\"Rice fields\",\"style_design\":\"Modern Minimalist\",\"surrounding\":null,\"imb\":null,\"zone\":\"YELLOW\",\"living_room_type\":\"Open-Closed\",\"dining_room_type\":\"Open-Closed\"