(674, 2, 'update', 'Property', 164, 'Updated property: VILLA UNFURNISHED MODERN DI MUNGGU CEPAKA', '{\"old\":{\"id\":164,\"admin_id\":\"2\",\"views\":\"19\",\"property_number\":\"PN260200009\",\"transaction_number\":\"00003\",\"title\":\"VILLA UNFURNISHED MODERN DI MUNGGU CEPAKA\",\"slug\":\"villa-unfurnished-modern-di-munggu-cepaka\",\"description\":\"Set in a peaceful pocket of Munggu, this modern villa features expansive floor-to-ceiling windows that flood the interior with natural light and frame the surrounding landscape beautifully. From the bedroom and living areas, you enjoy uninterrupted rice field greenery with a glimpse of the ocean in the distance \\u2014 a view combination that is increasingly difficult to find this close to Canggu.\\r\\n\\r\\nWith 22 years leasehold remaining, this villa presents an attractive opportunity for investors looking to enter the Bali market in an emerging location. Munggu is gaining attention as a quieter alternative to nearby Canggu, yet still close to beach clubs, restaurants, and surfing beaches \\u2014 making it highly appealing for short-term rental guests.\",\"property_type\":\"villas\",\"property_type_id\":\"1\",\"property_status\":\"AVAILABLE\",\"expired_date\":\"2026-08-17T17:00:00.000000Z\",\"pic_ref_number\":\"AGPRD01\",\"pic_name\":\"Diana\",\"pic_email\":null,\"pic_whatsapp_number\":\"+6281388305558\",\"price\":\"3500000000.00\",\"price_monthly\":null,\"price_yearly\":null,\"price_freehold\":null,\"price_leasehold\":\"3500000000.00\",\"leasehold_period\":22,\"has_monthly\":false,\"has_yearly\":false,\"location_text\":\"Cepaka\",\"area\":\"Tabanan\",\"latitude\":\"-8.60660370\",\"longitude\":\"115.14606170\",\"land_size\":\"112.00\",\"building_size\":\"172.00\",\"dimension\":\"10m x 11m\",\"direction\":\"East\",\"year_of_build\":\"2026\",\"floor_level\":\"2\",\"view\":\"Rice fields\",\"style_design\":\"Modern Minimalist\",\"surrounding\":null,\"imb\":null,\"zone\":\"YELLOW\",\"living_room_type\":\"Open-Closed\",\