INSERT INTO `advisor_guides` (`id`, `title`, `content`, `reference_url`, `reference_urls`, `published_at`, `is_active`, `created_at`, `updated_at`) VALUES
(2, 'Uluwatu Lagi Naik (Dan Kenapa Banyak Investor Mulai Masuk ke Sini)', 'Kalau kita ngomongin Bali, dulu orang pasti fokus ke Canggu atau Seminyak.\r\nTapi sekarang, makin sering kita dengar satu area ini:\r\n👉 Uluwatu\r\nDan ini bukan sekadar hype sesaat, kita lihat langsung dari demand yang mulai shifting ke sini.\r\n\r\n📊 Marketnya Kerasa Banget di 1–2 Tahun Terakhir\r\nSepanjang 2025, Bali terus naik dari sisi tourism. Tapi yang menarik, khusus untuk Uluwatu:\r\n- banyak tamu yang datang bukan cuma untuk liburan, tapi stay lebih lama\r\n- marketnya lebih ke arah lifestyle & experience-driven\r\n\r\nYang kita lihat di lapangan:\r\nBanyak inquiry untuk villa di Uluwatu - Ungasan\r\nShort-term rental tetap kuat, tapi long-stay mulai naik\r\nBanyak client cari land untuk development (bukan sekadar beli jadi)\r\nDan ini beda dengan beberapa tahun lalu, di mana Uluwatu lebih “seasonal”.\r\n\r\n🌊 Kenapa Banyak yang Mulai Pilih Uluwatu?\r\nSimple: vibe-nya beda\r\nKalau dibandingkan:\r\nCanggu → busy, social, crowded\r\nUbud → calm, jungle, wellness\r\nUluwatu → coastal, laid-back, tapi tetap premium\r\n\r\nUluwatu sekarang jadi sweet spot untuk:\r\nBeach lifestyle, Surf culture, High-end villa experience\r\nArea seperti Ungasan dan Pecatu mulai sering banget masuk request list client.\r\n\r\n🏡 Real Pattern yang Kita Lihat\r\nBeberapa client yang kita handle belakangan ini:\r\nAwalnya fokus di Canggu, tapi mulai concern dengan crowd & traffic, akhirnya explore Uluwatu\r\nDan banyak yang akhirnya pivot ke:\r\n👉 villa dengan ocean view\r\n👉 atau land dekat beach untuk development\r\nMenariknya mereka nggak cari “mass market villa” tapi lebih ke high-end / niche product\r\n\r\n💰 Soal Rental, Uluwatu Masih Kuat\r\nDari sisi angka:\r\nNightly rate cenderung lebih tinggi dibanding average Bali\r\nOccupancy bisa lebih fluktuatif (tergantung location & season)\r\nTapi…\r\n👉 villa dengan view (especially ocean/cliff) perform sangat kuat\r\n👉 property dengan design standout bisa charge premium\r\n\r\nYang kita lihat:\r\nProperti biasa → mulai susah compete\r\nProperti dengan concept kuat → masih sangat laku\r\nJadi, bukan soal banyak unit tapi soal positioning\r\n\r\n🍽️ Lifestyle = Value Driver\r\nUluwatu berkembang cepat karena lifestyle-nya makin kuat.\r\nTempat seperti:\r\nThe Cashew Tree\r\nDrifter Cafe\r\nSingle Fin\r\nbukan cuma ramai, tapi jadi bagian dari experience orang yang stay di area ini.\r\n\r\nSunset culture, beach club scene, surf and wellness community\r\nSemua ini bikin orang datang bukan cuma untuk tidur, tapi untuk lifestyle\r\n\r\n⚠️ Reality Check\r\nWalaupun lagi naik, ada beberapa hal yang harus realistis:\r\nDevelopment makin cepat\r\nBeberapa area mulai padat\r\nInfrastruktur di beberapa titik masih berkembang\r\nArtinya nggak semua lokasi di Uluwatu bagus, salah pilih land bisa impact ke rental performance\r\n\r\n✨ Jadi… Worth It?\r\nJawabannya: yes! tapi beda approach\r\n\r\nUluwatu bukan tempat untuk:\r\n❌ build villa standar\r\n❌ berharap occupancy tinggi tanpa concept\r\n\r\nTapi sangat cocok untuk:\r\n✅ boutique villa\r\n✅ design-driven property\r\n✅ high-end / experience-based stay', NULL, NULL, '2026-03-30 02:00:00', 1, '2026-03-29 01:14:00', '2026-03-31 06:55:24'),
(3, 'Uluwatu Advisor Note: Tempat-Tempat yang Lagi Hot Saat Ini', 'Kalau ngomongin Uluwatu sekarang, yang bikin area ini makin naik bukan cuma villa atau view, tapi lifestyle di sekitarnya. Dan jujur, beberapa spot ini sekarang hampir selalu jadi referensi client waktu mereka decide mau stay atau invest di sini.\r\n\r\n🍽️ Yang Lagi Ramai & Konsisten Full\r\nBeberapa tempat ini hampir selalu masuk list:\r\n1. The Cashew Tree\r\n→ crowd-nya mix: expat, surfer, long-stay guest\r\n→ vibe santai tapi tetap lively\r\n2. Drifter Cafe\r\n→ salah satu spot paling konsisten dari dulu\r\n→ kuat di branding & community\r\n3. Ours\r\n→ lebih modern, banyak short-term guest\r\n→ sering jadi breakfast/brunch spot pilihan\r\n\r\nKalau di Uluwatu, sunset itu bukan bonus, tapi bagian dari lifestyle.\r\n1. Single Fin\r\n→ iconic, hampir semua orang pasti ke sini\r\n→ peak time: Sunday session\r\n2. Uluwatu Temple\r\n→ bukan cuma tourist spot, tapi experience\r\n→ Kecak + sunset masih jadi magnet besar\r\n3. Nyang Nyang Beach\r\n→ lebih sepi, tapi justru itu daya tariknya\r\n→ mulai banyak dilirik untuk nearby development\r\n\r\n🏖️ Beach Area yang Lagi Dicari Client\r\nBeberapa area ini hampir selalu muncul waktu client cari lokasi:\r\n1. Bingin Beach\r\n→ salah satu yang paling “in demand”\r\n→ cocok untuk rental market\r\n2. Padang Padang\r\n→ akses mudah + terkenal\r\n→ kuat di short-term stay\r\n3. Melasti Beach\r\n→ berkembang cepat\r\n→ banyak beach club & project baru\r\n\r\n🧠 Advisor Insight\r\nYang menarik dari semua ini: orang datang ke Uluwatu bukan cuma cari villa, tapi cari experience di sekitar villa. Dan biasanya semakin dekat ke ecosystem ini, semakin gampang property itu perform. Makanya sekarang banyak client nggak cuma tanya: “berapa harga land?” tapi “dekat apa aja?”, “vibe area-nya gimana?”.\r\n\r\n✨ Quick Take\r\nKalau disederhanakan:\r\n👉 Uluwatu sekarang dijual oleh lifestyle, bukan sekadar property\r\n👉 dan spot-spot ini yang jadi “anchor” value area', NULL, NULL, '2026-04-03 02:00:00', 1, '2026-04-02 11:34:26', '2026-04-02 11:37:05'),
(4, 'Pererenan - New Canggu?', 'Beberapa tahun lalu orang lihat Pererenan sebagai “sebelahnya Canggu”. Sekarang justru banyak yang mulai lihat Pererenan sebagai alternatif utama.\r\n\r\n📊 Demand Sudah Masuk, Bukan Baru Mulai\r\nDalam 12–18 bulan terakhir:\r\n- inquiry untuk Pererenan naik cukup signifikan\r\n- banyak client langsung mention area ini (bukan lagi “optional”)\r\n- villa rental di sini mulai perform stabil\r\n\r\nYang menarik:\r\nBanyak tamu yang stay di Canggu → extend stay di Pererenan\r\nBanyak yang bilang: “lebih enak, lebih tenang”\r\n\r\n🌊 Kenapa Orang Mulai Pilih Pererenan?\r\nSimple: masih dekat ke semuanya, tapi nggak sepadat Canggu\r\nDari Pererenan:\r\n5–10 menit ke hotspot Canggu\r\nAkses ke beach tetap mudah\r\nTapi vibe-nya lebih relaxed\r\n\r\nIni jadi sweet spot untuk:\r\nLong-stay guest\r\nDigital nomad\r\nBahkan small family\r\n\r\n🏡 Real Pattern di Market\r\nYang kita lihat sekarang:\r\nClient dengan budget mid–high, mulai skip Canggu, langsung fokus Pererenan.\r\nKenapa?\r\n- masih bisa dapat value lebih baik\r\n- environment lebih nyaman untuk tinggal\r\nTapi di saat yang sama…\r\n- harga sudah mulai naik\r\n- land availability mulai terbatas\r\n\r\n💰 Soal Investment\r\nPererenan sekarang ada di posisi yang menarik, bukan early lagi, tapi belum fully mature\r\nArtinya, masih ada upside, tapi harus lebih selective\r\n\r\nYang perform bagus:\r\nVilla dengan design clean & modern\r\nProperti dengan walking distance ke beach / café\r\n\r\nYang mulai struggle:\r\nProduk “biasa” tanpa positioning\r\n\r\n🍽️ Lifestyle yang Mulai Kuat\r\nYang bikin Pererenan makin solid:\r\nCafé & restaurant mulai banyak dan bagus\r\nCrowd lebih “mature” dibanding Canggu\r\nLebih cocok untuk stay lama\r\nDan ini penting:\r\n👉 orang yang stay lebih lama = stabilitas rental lebih baik\r\n\r\n\r\n✨ Quick Take\r\nKalau disimplify:\r\n👉 Pererenan = versi lebih calm dari Canggu\r\n👉 demand sudah terbukti\r\n👉 tapi entry harus lebih smart', NULL, NULL, '2026-04-06 02:00:00', 1, '2026-04-08 05:06:29', '2026-04-08 05:06:40');
