(1, 1, 136, 'PN251200001', NULL, 'Stunning houses in Tabanan', 'stunning-houses-in-tabanan-5240', 'Exclusive property in gated community with premium security. Features 6 bedrooms and 5 bathrooms. Located in the heart of Tabanan, Bali, this property offers excellent value and potential.', 'houses', 2, 'AVAILABLE', '2026-06-17', 'PIC-KET-7010', 'Ketut Sari', 'ketut.sari@baliproperty.com', '+628426206841', 10072716184.72, 28143039.00, 0.00, 0.00, 10072716184.72, 25, 1, 0, 'Tabanan, Bali', NULL, -8.52920000, 115.11750000, 359.01, 222.59, '25m x 40m', 'North', 2022, 2, 'Garden View', 'Traditional', 'Close to restaurants, shopping centers, beaches, and main roads. Safe and quiet neighborhood with excellent amenities.', 'IMB-7222/2025', 'GREEN', 'Closed', 'Open', 'Open', 6, 5, 2, 'Home Office', 'Built-in Storage', 1, 1, 1, 1, 'Semi Furnished', '11000 VA', 2, 'Well Only', 'Not Available', 'Carport', '3', 'Property tax, security, maintenance, and utilities', 1, 1, 1, 1, 1, 1, 1, 1, 'Great investment opportunity. Property is well-maintained and ready for immediate use.', '2025-12-19 07:42:55', '2026-04-07 18:34:55', 0, NULL),
(76, 2, 16, 'PN260100021', NULL, 'VILLA TERBESAR DI KOMPLEKS VILLA KOMERSIAL – UNGASAN', '4-br-the-largest-villa-in-a-commercial-villa-complex-ungasan', 'Villa ini berlokasi di Jalan Mangelak, komplek villa Hideaway Residence Ungasan. Sebuah komplek villa elite yang tertata rapi, well maintenance dan high occupancy 75-88% . Lebar jalan komplek 6 meter. Villa ini terdiri dari 2 lantai. Lantai 1 terdapat main area (living room, kitchen, dining area, service room, kolam berenang, dan carport untuk 2 mobil. Sedangkan lantai 2  terdapat kamar, balkon dan family room. Villa di komplek ini rata-rata di sewakan harian di harga 2 - 3,5 juta untuk 2 kamar tidur. So, kamu bisa sewakan villa 4 kamar ini di harga 3,5-5 juta per malamnya.\r\n\r\nSemua villa di komplek ini di handle oleh management.\r\n\r\nNearby Locations:\r\nNourish Café Pecatu – 2.6 km (7 minutes)\r\nPecatu Golf Area – 2.7 km (8 minutes)\r\nGWK Gate Entrance – 3.1 km (9 minutes)\r\nMelasti Beach – 3.6 km (8 minutes)\r\nSavaya Beach Club – 4.8 km (14 minutes)', 'villas', 1, 'AVAILABLE', '2027-02-27', 'PPB12MAE', 'Pemburu Property Bali', 'pemburupropertybali@gmail.com', '+6281237741674', 7500000000.00, NULL, NULL, 7500000000.00, NULL, NULL, 0, 0, 'Jl Mangelak', 'Ungasan', -8.82885390, 115.15898640, 405.00, 436.00, '18.4m x 22m', NULL, NULL, 2, 'Residence', 'Tropical Modern', NULL, NULL, 'YELLOW', 'Open-Closed', 'Open-Closed', 'Open-Closed', 4, 4, NULL, '0', '1', 1, 0, 1, 0, 'Fully Furnished', '7700', NULL, 'PDAM', NULL, 'Private', NULL, NULL, 1, 0, 0, 0, 0, 0, 0, 0, 'Semua villa di dalam komplek ini di managed oleh management.', '2026-01-06 05:12:30', '2026-04-07 18:29:41', 0, NULL),
(192, 2, 22, 'PN260300021', '00001', 'TANAH 98 ARE DIBAWAH KAKI GUNUNG BATUKARU - TABANAN', 'dijual-tanah-dibawah-kaki-gunung-batu-karu-tabanan', 'Tanah seluas 98 are ini terletak dibawah kaki Gunung Batukaru dan berhadapan langsung dengan sungai kecil sebagai sumber air di sisi barat. Tanah ini memiliki pemandangan sawah terasering yang indah, dan kontur tanah yang tinggi - menurun menjadikan tanah ini primadona bagi mereka yang mencintai alam yang asri, air yang jernih dan udara yang sejuk.', 'land', 4, 'AVAILABLE', '2027-03-26', 'PPB12MAE', 'Mellyta', 'balimellytaa@gmail.com', '+62 812-3774-1674', 11000000000.00, NULL, NULL, 11000000000.00, NULL, NULL, 0, 0, 'Jl. Gn. Salak', 'Tabanan', -8.45448890, 115.06506690, 9800.00, NULL, 'Barat 163.79m x Timur 72.53m x ⁠Utara 107m x ⁠Selatan 86.69m', 'East', NULL, NULL, NULL, NULL, 'Sawah', NULL, 'YELLOW', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 0, 0, 0, 0, NULL, NULL, NULL, 'Sumur Bor & PDAM', NULL, NULL, NULL, NULL, 1, 0, 0, 0, 0, 0, 0, 0, 'Kontur = Tinggi- menurun\r\nAkses jalan = Aspal 5 meter', '2026-03-29 00:49:46', '2026-04-07 18:32:29', 0, NULL),
(77, 2, 13, 'PN260100022', NULL, 'RUMAH SEMI VILLA DEKAT PANTAI MELASTI - UNGASAN', '5-br-urgent-sale-2-floors-villa-at-jl-pura-masuka', 'Nearby Location :\r\nFour Points Hotell Ungasan - 550 m (3 mins)\r\nGWK Gate entrance - 600 meter (3 mins)\r\nSidewalk Mall Jimbaran - 1.6 km (7 mins)\r\nSunday Beach Club - 6 km (18 mins)', 'villas', 1, 'AVAILABLE', '2027-02-27', 'PPB12MAE', 'Pemburu Property Bali', 'pemburupropertybali@gmail.com', '+6281237741674', 7600000000.00, NULL, NULL, 7600000000.00, NULL, NULL, 0, 0, 'Jl Pura Masuka', 'Ungasan', -8.82920560, 115.15023050, 350.00, 450.00, NULL, NULL, 2023, 2, 'Residence', 'Minimalist Modern', NULL, NULL, 'YELLOW', 'Closed', 'Closed', 'Closed', 5, 5, NULL, NULL, NULL, 1, 0, 0, 0, 'Fully Furnished', '5500', NULL, 'PDAM', NULL, 'Private', NULL, NULL, 1, 0, 0, 0, 0, 0, 0, 0, 'Terletak di Jalan Pura Masuka, dekat ke Pantai melasti dan juga area Ungasan seperti resto, cafe, market, dll.', '2026-01-06 05:16:00', '2026-04-07 18:29:40', 0, NULL),
(89, 2, 13, 'PN260100034', NULL, 'CLUSTER VILLA MODERN MINIMALIST DI SEMINYAK', 'villa-tropis-modern-3-kamar-tidur-di-seminyak', 'Rumah semi villa ini berada di cluster dengan pemandangan sawah dari lantai 2. Area super tenang dan dekat dengan central pariwisata. Cocok untuk dijadikan hunian priadi, rumah singgah, atau disewakan di harian karena lokasi yang dekat kemana-mana, dan disewakan bulanan bahkan tahunan karena tempatnya yang super nyaman.\r\n\r\nLokasi Terdekat :\r\nBabi Guling pak Malen - 1.9 km (6 menit)\r\nSushi Hiro Sunsetroad - 1.9 km (6 menit)\r\nSeminyak Beach - 3 km (10 mins) \r\nPetitenget Beach - 4.1 km (16 mins)', 'villas', 1, 'AVAILABLE', '2027-02-27', 'PPB12MAE', 'Pemburu Property Bali', 'pemburupropertybali@gmail.com', '+6281237741674', 4300000000.00, NULL, NULL, 4300000000.00, NULL, NULL, 0, 0, 'Jl Beji Ayu', 'Seminyak', -8.69537470, 115.17664430, 118.00, 120.00, NULL, 'North', 2023, 2, 'Sawah', 'Minimalis modern', NULL, NULL, 'YELLOW', 'Open-Closed', 'Open-Closed', 'Open-Closed', 2, 2, NULL, NULL, '1', 1, 1, 1, 1, 'Fully Furnished', '5500', 3, 'PDAM', NULL, 'Private', '0', NULL, 1, 0, 0, 0, 0, 0, 0, 0, 'Berada di cluster dengan lokasi yang sangat prime.', '2026-01-12 01:45:16', '2026-04-07 18:31:54', 0, NULL),
(78, 2, 17, 'PN260100023', NULL, 'VILLA PUTIH KEMBAR DI BUKIT BINTANG - UNGASAN', '3-br-brand-new-villa-in-bukit-bintang-ungasan-2', 'Villa ini berlokasi di area Bukit Bintang, sebuah area tinggi di Ungasan dengan akses jalan aspal yang cukup lebar (10 meter) dan pemandangan laut, tol, bandara, hingga GWK. Di area ini banyak sekali villa-villa mewah dan megah berdiri. Untuk villa ini, pemandangan terlihat dari kedua balkon kamar yang menghadap ke Selatan. \r\n\r\nLokasi terdekat : \r\nCoco Mart - 1.2 km (5 menit)\r\nGWK Gate Entrance - 2.2 km (7 menit)\r\nSidewalk Mall Jimbaran - 2.9 km (9 menit)\r\nPantai Jimbaran - 4.5 km (13 menit)\r\nPecatu Golf - 4.7 km (14 menit)', 'villas', 1, 'AVAILABLE', '2027-02-27', 'PPB12MAE', 'Pemburu Property Bali', 'pemburupropertybali@gmail.com', '+6281237741674', 7900000000.00, NULL, NULL, 7900000000.00, NULL, NULL, 0, 0, 'Jl Kintamani', 'Ungasan', -8.80912500, 115.15388000, 195.00, 250.00, '10m x 19.5m', NULL, 2025, 2, 'Residence & Laut', 'Modern', NULL, NULL, 'YELLOW', 'Open-Closed', 'Open-Closed', 'Open-Closed', 3, 4, NULL, NULL, NULL, 1, 0, 1, 0, 'Semi Furnished', '7700', NULL, 'PDAM', NULL, 'Private', '1 Car ; 2 bike', NULL, 1, 0, 0, 0, 0, 0, 0, 0, NULL, '2026-01-06 05:18:40', '2026-04-07 18:32:28', 0, NULL),
(92, 2, 16, 'PN260100037', NULL, 'VILLA BERKONSEP TRADISIONAL BALINESE DI KEROBOKAN', 'villa-tradisional-bali-kerobokan', 'Villa ini terletak di tepat di pinggir jalan Pengubengan Kauh - Kerobokan dengan akses jalan 6 meter. Lokasinya sangat strategis, hanya 1 km jalan kaki ke Livingstone Cafe, dan beberapa meter ke lapas Kerobokan. Area sekitar didominasi oleh villa-villa dan restaurant. Dengan konsep Tradisional Balinesse, villa ini sangat cocok menemani masa pensiun kamu!\r\n \r\n\r\nLokasi Terdekat :\r\nBebek Patmoroso - 350 meter (1 menit)\r\nKIOA Bali - 700 Meter (3 menit)\r\nLivingstone -1.0 km (4 menit) \r\nPantai Petitenget- 2.9 km (11 menit) \r\nPantai Batu Belig - 4.6 km (15 menit)', 'villas', 1, 'AVAILABLE', '2027-02-27', 'PPB12MAE', 'Pemburu Property Bali', 'pemburupropertybali@gmail.com', '+6281237741674', 5000000000.00, NULL, NULL, 5000000000.00, NULL, NULL, 0, 0, 'Kerobokan', 'Kerobokan', -8.66755860, 115.16701730, 300.00, 200.00, NULL, NULL, NULL, 2, NULL, 'Tropical Balinese', NULL, NULL, 'YELLOW', 'Open', 'Open', 'Open', 2, 3, NULL, NULL, NULL, 1, 0, 0, 0, 'Fully Furnished', '7500', 2, 'PDAM', NULL, 'Private', NULL, NULL, 1, 0, 0, 0, 0, 0, 0, 0, 'Terletak di pinggir jalan, area parkir hanya cukup untuk 1 mobil. Kamar kedua terletak di atas kamar pertama.', '2026-01-12 03:22:50', '2026-04-07 18:33:14', 0, NULL),
