(97, 2, 14, 'PN260100042', NULL, 'VILLA MEWAH 500 METER KE PANTAI BATU BOLONG - CANGGU', 'villa-mewah-300-meter-dari-echo-beach-canggu', 'Dengan jarak 500 meter dari pantai, villa ini termasuk salah satu villa yang dijual dengan harga dibawah pasaran. Cocok disewakan harian karena hanya jalan kaki menuju restaurant, cafe, pertokoan, salon, club, dan lainnya. Sangat direkomendasikan untuk kamu yang mencintai area Canggu dan hanya jalan kaki untuk ke pantainya!\r\n\r\nLokasi Terdekat :\r\nDesa Kitsune Bali - 250 meter (1 menit)\r\nGigi Susu - 500 meter (2 Menit)\r\nPantai Batu Bolong - 500 meter (2 menit)\r\nLa Brisa Bali Beach Club - 1 km (4 Menit)\r\nCOMO beach Club Canggu - 1.1km (4 menit)', 'villas', 1, 'AVAILABLE', '2027-02-27', 'PPB12MAE', 'Pemburu Property Bali', 'pemburupropertybali@gmail.com', '+6281237741674', 8300000000.00, NULL, NULL, 8300000000.00, NULL, NULL, 0, 0, 'Jl Munduk Catu', 'Canggu', -8.65495540, 115.12698870, 225.00, 200.00, NULL, 'South', 2019, 2, 'Residence', 'Tropical Minimalist', 'Villa, apartment dan restaurant', NULL, 'PINK', NULL, NULL, NULL, 3, 4, NULL, NULL, NULL, 1, 0, 0, 0, 'Fully Furnished', '7500', 4, 'PDAM', NULL, 'Private', NULL, NULL, 1, 0, 0, 0, 0, 0, 0, 0, 'Lokasi sangat tenang, hanya jalan kaki kemana-mana, dan cocok disewakan harian.', '2026-01-12 03:57:07', '2026-04-07 18:32:33', 0, NULL),
