(114, 2, 31, 'PN260100058', NULL, 'VILLA MEWAH DI PERERENAN', 'luxury-villa-in-heart-of-pererenan', 'Villa ini berjarak hanya 50 meter dari Jalan Raya Pererenan. Lingkungannya 100% villa-villa. Villa mewah ini biasanya disewakan di bulanan dengan harga 100 juta. Untuk akses jalan terbilang cukup mudah diakses dan dicari. Vibrasi di dalam villa ini pun cukup tenang dan nyaman, sehingga cocok untuk dijadikan hunian pribadi ataupun disewakan jangka panjang. \r\n\r\nLokasi dekat dengan : \r\nObsidian Gym - 300 meter (1 menit)\r\nNude Cafe Pererenan - 350 meter (2 menit)\r\nPantai Pererenan - 3.3 km (8 menit)\r\nLa Brisa Beach Clun - 3.5 km (10 menit)\r\nPantai Batu Bolong - 4.1 km (13 menit)', 'villas', 1, 'AVAILABLE', '2027-02-27', 'PPB12MAE', 'Pemburu Property Bali', 'pemburupropertybali@gmail.com', '+6281237741674', 15000000000.00, NULL, NULL, 15000000000.00, NULL, NULL, 0, 0, 'Pererenan', 'Pererenan', -8.63292000, 115.13914400, 490.00, 500.00, NULL, 'South', NULL, 2, 'Residence', 'Minimalist Modern', NULL, NULL, 'YELLOW', 'Open-Closed', 'Open-Closed', 'Open-Closed', 4, 4, NULL, NULL, '1', 1, 0, 1, 1, 'Fully Furnished', '13000', 5, 'PDAM', NULL, 'Private', '2 Car ; 2 Bike', NULL, 1, 0, 0, 0, 0, 0, 0, 0, NULL, '2026-01-15 09:50:36', '2026-04-07 18:31:50', 0, NULL),
