(73, 2, 14, 'PN260100018', NULL, '4 BR VILLA GAYA SANTORINI DEKAT PANTAI MELASTI – UNGASAN', '4-br-santorini-style-villa-near-melasti-beach-ungasan', 'Villa bergaya Santorini ini terletak di Jalan Tukad Selatan dan berjarak 3 km dari Pantai Melasti, dekat dengan Mega Project 4 PT PMA yang membangun kawasan Ungasan seluas 4 hektar. Lingkungan sekitar terbilang tenang, banyak rumah lokal dan villa-villa yang sedang di bangun. Villa ini memiliki peluang potensial yang cukup tinggi mengingat area sekitar sedang di develop oleh investor dalam negeri dan luar negeri. Range harga sewa per malam untuk 4 bedroom di area sekitar di harga 3-4.5 juta atau bisa disewakan di tahunan di harga 550 - 600 juta.', 'villas', 1, 'AVAILABLE', '2027-02-27', 'PPB12MAE', 'Pemburu Property Bali', 'pemburupropertybali@gmail.com', '+6281237741674', 5000000000.00, NULL, NULL, 5000000000.00, 4550000000.00, 20, 0, 0, 'Jl Tukad Selatan', 'Ungasan', -8.83313970, 115.15447010, 165.00, 300.00, '10m x16.5m', 'West', 2023, 3, 'Residence', 'Santorini', NULL, NULL, 'YELLOW', 'Open', 'Open', 'Open', 4, 5, NULL, NULL, '1', 1, 0, 0, 0, 'Fully Furnished', '7700', 5, 'PDAM', NULL, 'Private', '1 Car ; 2 bike', NULL, 1, 0, 0, 0, 0, 0, 0, 0, 'Cocok untuk disewakan harian.\r\n\r\nNearby Locations:\r\nMelasti Beach – 3 km (7 mins)\r\nWhite Rock Beach Club – 3 km (7 mins)\r\nGWK Gate Entrance – 5.7 km (12 mins)\r\nPandawa Beach – 6.3 km (15 mins)', '2026-01-05 06:03:27', '2026-04-07 18:31:58', 0, NULL),
(75, 2, 14, 'PN260100020', NULL, 'VILLA KOMERSIAL DEKAT SIDEWALK MALL – JIMBARAN', '21-br-commercial-villa-near-sidewalk-mall-jimbaran', 'Villa ini terletak beberapa ratus meter dari Mall Sidewalk Jimbaran atau Moven Pick Resort. Lokasinya cukup strategis karena dekat dengan mall, resort mewah, pasar, sekolah, dan cafe/restaurant. Villa ini dibangun untuk komersial sehingga sejak dibangun sampai sekarang selalu disewakan di harga 50-60 juta per bulan dan rata-rata penyewa adalah Foreigner Rusia. Jadi jika tujuan kamu adalah mencari passive income, villa ini sangat cocok karena kamu tinggal melanjutkan rental property ini.', 'villas', 1, 'AVAILABLE', '2027-02-27', 'PPB12MAE', 'Pemburu Property Bali', 'pemburupropertybali@gmail.com', '+6281237741674', 6000000000.00, NULL, NULL, 6000000000.00, NULL, NULL, 0, 0, 'Jl Raya Uluwatu', 'Jimbaran', -8.79328180, 115.16228600, 200.00, 200.00, '10m x 20m', 'South', NULL, 2, 'Residence', NULL, NULL, NULL, 'YELLOW', 'Open-Closed', 'Open-Closed', 'Open-Closed', 3, 3, NULL, '2', '1', 1, 0, 1, 0, 'Fully Furnished', '7700', 3, 'PDAM', NULL, 'Private', '1 Car ; 2 bike', NULL, 1, 0, 0, 0, 0, 0, 0, 0, 'Nearby Locations:\r\nSidewalk Mall Jimbaran – 500 m (2 mins)\r\nGWK Gate Entrance – 1 km (5 mins)\r\nJimbaran/Muaya/Kedonganan Beach – 1.9 km (8 mins)\r\nMovenpick Resort – 2.1 km (10 mins)\r\nUdayana University – 2.2 km (10 mins)\r\nBali Jimbaran General Hospital – 4.1 km (13 mins)', '2026-01-05 06:08:07', '2026-04-07 18:26:53', 0, NULL),
