(162, 1, 24, 'PN260200007', '00001', 'KOST 64 KAMAR DI AREA KAMPUS UDAYANA - JIMBARAN', 'kost-64-kamar-di-area-kampus-udayana-jimbaran', 'Cocok untuk investor yang mencari aset high-demand di area kampus dengan potensi cashflow stabil & capital gain jangka panjang.\r\n\r\nFully furnished dengan :\r\nAC inverter, Smart TV (32” & 43”), WiFi Biznet, ranjang 160x200 memory foam, rooftop 360° unblocking view.', 'apartments', 3, 'AVAILABLE', '2027-02-27', 'PPB12MAE', 'Mellyta', 'balimellytaa@gmail.com', '+62 812-3774-1674', 24000000000.00, 2500000.00, NULL, 24000000000.00, NULL, NULL, 1, 0, 'Jimbaran', 'Jimbaran', -8.80267900, 115.17241700, 602.00, 2408.00, '20m x 30m', 'West', 2025, 4, 'Residence', NULL, NULL, NULL, NULL, 'Closed', 'Closed', 'Closed', 64, 64, NULL, NULL, '1', 0, 1, 1, 0, 'Fully Furnished', '13.000', NULL, 'PDAM', NULL, 'Central', NULL, NULL, 1, 0, 0, 0, 0, 0, 0, 0, 'Kos-kosan ini dijual 2 gedung. Namun bisa dibeli salah satu gedung saja di harga IDR 12,000,000,000. IMB/PBG dalam proses penerbitan.', '2026-02-18 02:54:20', '2026-04-08 08:02:11', 0, NULL),
(163, 1, 16, 'PN260200008', '00001', 'VILLA MODERN KONTEMPORER DENGAN PEMANDANGAN SAWAH DI PEJENG', 'villa-modern-kontemporer-dengan-pemandangan-sawah-di-pejeng', 'Lokasi terdekat :\r\n* ATV Rafting Ubud - 350 meter (1 menit)\r\n* Ubud Market - 6 km ( 17 menit)\r\n* Aperitif Restaurant Fine Dining Ubud - 6.8 km (18 menit)\r\n* BIMC Ubud Hostpital - 9 km (26 menit)', 'villas', 1, 'AVAILABLE', '2027-02-27', 'PPB12MAE', 'Mellyta', 'balimellytaa@gmail.com', '+62 812-3774-1674', 5300000000.00, NULL, NULL, 5300000000.00, NULL, NULL, 0, 0, 'Jalan Raya Pejeng Kawan', 'Ubud', -8.48223600, 115.28484000, 194.00, 268.00, NULL, NULL, 2025, 2, 'Ricefield', NULL, NULL, 'ada', 'YELLOW', 'Open-Closed', 'Open-Closed', 'Open-Closed', 3, 4, NULL, NULL, '1', 1, 0, 1, 0, 'Fully Furnished', '7700', NULL, 'Sumur Bor', NULL, 'Private', '1 Car ; 2 bike', NULL, 1, 0, 0, 0, 0, 0, 0, 0, 'Berada di komplek villa dengan akses jalan 5 meter paving dan suasana yang sangat tenang.', '2026-02-18 03:09:30', '2026-04-07 18:25:39', 0, NULL),
(164, 2, 28, 'PN260200009', '00003', 'VILLA UNFURNISHED MODERN DI MUNGGU CEPAKA', 'villa-unfurnished-modern-di-munggu-cepaka', 'Set in a peaceful pocket of Munggu, this modern villa features expansive floor-to-ceiling windows that flood the interior with natural light and frame the surrounding landscape beautifully. From the bedroom and living areas, you enjoy uninterrupted rice field greenery with a glimpse of the ocean in the distance — a view combination that is increasingly difficult to find this close to Canggu.\r\n\r\nWith 22 years leasehold remaining, this villa presents an attractive opportunity for investors looking to enter the Bali market in an emerging location. Munggu is gaining attention as a quieter alternative to nearby Canggu, yet still close to beach clubs, restaurants, and surfing beaches — making it highly appealing for short-term rental guests.', 'villas', 1, 'AVAILABLE', '2026-08-18', 'AGPRD01', 'Diana', NULL, '+6281388305558', 3500000000.00, NULL, NULL, NULL, 3500000000.00, 22, 0, 0, 'Cepaka', 'Tabanan', -8.60660370, 115.14606170, 112.00, 172.00, '10m x 11m', 'East', 2026, 2, 'Rice fields', 'Modern Minimalist', NULL, NULL, 'YELLOW', 'Open-Closed', 'Open-Closed', 'Open-Closed', 2, 1, 2, NULL, NULL, 1, 0, 1, 0, 'Non Furnished', '7700', 3, 'PDAM', NULL, 'Private', '1 car + 2 motorcycle', NULL, 1, 0, 0, 0, 0, 0, 0, 0, NULL, '2026-02-19 08:47:28', '2026-04-07 18:24:58', 0, NULL),
(165, 2, 41, 'PN260200010', '00003', 'VILLA MODERN TROPICAL DI UMALAS', 'villa-modern-tropical-di-umalas', 'A hidden gem in Umalas. ✨\r\n\r\nThis charming tropical villa combines comfort, style, and Bali’s signature indoor–outdoor living. Featuring open spaces, natural textures, and a private pool surrounded by greenery, it offers the perfect atmosphere for relaxation.\r\n\r\nLocated in one of Bali’s most strategic areas —\r\n* 10 minutes to Canggu\r\n* 5 minutes to Seminyak\r\n* Surrounded by cafes, restaurants, and international communities\r\n\r\nUmalas has become one of the most desirable locations for both long-term living and rental investment.\r\n\r\nA peaceful oasis in the middle of Bali’s most vibrant lifestyle.', 'villas', 1, 'AVAILABLE', '2026-08-18', 'AGPRD03', 'Diana', NULL, '+6281388305558', 7900000000.00, NULL, NULL, 7900000000.00, NULL, NULL, 0, 0, 'Umalas', 'Kerobokan', -8.65521910, 115.15332410, 400.00, 210.00, '35m x 35m', 'South', 2024, 1, 'Trees', 'Modern Tropical', NULL, NULL, 'YELLOW', 'Open-Closed', 'Open-Closed', 'Open', 4, NULL, 4, NULL, '1', 1, 0, 0, 0, 'Fully Furnished', '7700', NULL, 'Sumur Bor & PDAM', NULL, 'Private', '2 cars', NULL, 1, 0, 0, 0, 0, 0, 0, 0, NULL, '2026-02-19 09:07:41', '2026-04-07 18:26:08', 0, NULL),
