(172, 2, 27, 'PN260300001', '00001', 'LUXURY VILLA DENGAN PEMANDANGAN LAUT JIMBARAN', 'luxury-villa-dengan-pemandangan-laut-jimbaran', 'Vila mewah dengan pemandangan laut yang memukau, terletak di lokasi strategis dengan suasana tenang dan privat, properti ini menawarkan kombinasi sempurna antara kenyamanan dan kemewahan.\r\n\r\nLokasi terdekat:\r\nGaruda Wisnu Kencana Cultural Park: 12 min drive.\r\nMelasti Beach : 15 min drive.\r\nHabit Coffee Bali: 4 min drive.\r\nNgurah Rai Airport: 27 min drive', 'villas', 1, 'AVAILABLE', '2027-03-03', 'PPB12MAE', 'Mellyta', 'balimellytaa@gmail.com', '+62 812-3774-1674', 38000000000.00, NULL, NULL, 38000000000.00, NULL, NULL, 0, 0, 'Jl. Melang Kaja', 'Kutuh', -8.80999470, 115.17937610, 43000.00, 1800.00, NULL, 'East', 2025, 2, 'Ocean', 'Luxury Modern Elegant', 'Villa-villa', 'Ada', 'YELLOW', 'Open-Closed', 'Open-Closed', 'Open-Closed', 6, 2, 6, '2', '2', 1, 1, 1, 1, 'Fully Furnished', '16.500', 8, 'Air tangki supplier', 'Ada', 'Private', '15 Car', NULL, 1, 0, 0, 0, 0, 0, 0, 0, NULL, '2026-03-03 05:12:50', '2026-04-07 18:29:35', 0, NULL),
(173, 2, 26, 'PN260300002', '00001', 'VILLA MEWAH DENGAN PEMANDANGAN LAUT DAN SUNSET DI JALAN PANTAI BALANGAN', 'villa-mewah-dengan-pemandangan-laut-dan-sunset-di-jalan-pantai-balangan', 'Villa sudah fully operasional, punya brand yang sudah dikenal dan track record sewa yang terbukti.\r\n\r\nRata-rata pendapatan bulanan: 75+ juta rupiah.\r\nDengan proyeksi kenaikan harga properti sekitar 7% per tahun, nilainya bertambah sekitar 1 miliar rupiah per tahun.', 'villas', 1, 'AVAILABLE', '2027-03-09', 'PPB12MAE', 'Mellyta', 'balimellytaa@gmail.com', '+62 812-3774-1674', 16500000000.00, NULL, NULL, 16500000000.00, NULL, NULL, 0, 0, 'Jl Pantai Balangan', 'Ungasan', -8.80297800, 115.13195200, 550.00, 500.00, NULL, 'East', 2008, 2, 'Laut dan sunset', 'Modern Tropical', 'Villa-villa', 'Ada', 'PINK', 'Open-Closed', 'Open-Closed', 'Open-Closed', 4, NULL, 4, '1', '1', 1, 0, 1, 0, 'Fully Furnished', '16,500', 5, 'PDAM', 'Ada', 'Private', '3 Car', NULL, 1, 0, 0, 0, 0, 0, 0, 0, NULL, '2026-03-09 02:04:03', '2026-04-07 18:25:00', 0, NULL),
(174, 2, 67, 'PN260300003', '00001', 'VILLA BARU DENGAN ROI 12% DEKAT ULUWATU', 'villa-baru-dengan-roi-12-dekat-uluwatu', 'Villa baru dekat Uluwatu dengan desain modern dan potensi ROI hingga 12%. Berada di area yang sedang berkembang dengan permintaan sewa yang tinggi, cocok untuk investasi sekaligus tempat tinggal. Pilihan tepat bagi yang mencari properti Bali yang stylish dengan potensi keuntungan menarik.', 'villas', 1, 'AVAILABLE', '2027-03-09', 'PPB12MAE', 'Mellyta', 'balimellytaa@gmail.com', '+62 812-3774-1674', 4500000000.00, NULL, NULL, NULL, 4500000000.00, 25, 0, 0, 'Jl Jimbaran - Uluwatu', 'Ungasan', -8.81998970, 115.14952010, 140.00, 180.00, '11.7 m x 12 m', 'West', 2026, 2, 'Residential', 'Modern Tropical', 'Villa-villa', 'Ada', 'YELLOW', 'Open-Closed', 'Open-Closed', 'Open-Closed', 2, 1, 2, NULL, '1', 1, 0, 1, 0, 'Fully Furnished', '2200', 2, 'PDAM', 'Ada', 'Private', '1 car', NULL, 1, 0, 0, 0, 0, 0, 0, 0, NULL, '2026-03-09 02:30:06', '2026-04-07 18:25:00', 0, NULL),
