(195, 2, 5, 'PN260400003', '00002', 'VILLA KELUARGA LUAS DENGAN 5 KAMAR TIDUR DI BENOA', 'villa-widya-ayu', 'Villa ini menawarkan ruang luas dan layout ideal untuk hunian keluarga maupun investasi. Berlokasi di Benoa, area yang tenang namun tetap dekat dengan berbagai akses utama.\r\nMemiliki bangunan multi-level dengan rooftop area yang cocok untuk santai atau entertaining. Desain tropis modern dengan pencahayaan alami, serta area outdoor yang nyaman.\r\nCocok untuk residence maupun rental investment dengan potensi yang menarik.', 'villas', 1, 'DRAFT', '2026-10-03', 'PRPDT88', 'PROSPEDITY', 'prospedity@gmail.com', '+6281958888351', 9000000000.00, NULL, NULL, 9000000000.00, NULL, NULL, 0, 0, 'Jl. Palapa', 'Benoa', -8.81110370, 115.18605580, 496.00, 375.00, '20m x 25m', 'East', 2016, 3, 'Benoa Bay, GWK', NULL, 'Villa-villa', 'Ada', 'YELLOW', NULL, NULL, NULL, 5, 1, 5, NULL, NULL, 1, 1, 1, 0, 'Fully Furnished', '15000', NULL, 'PDAM', NULL, 'Private', '2 cars', NULL, 0, 0, 0, 0, 0, 0, 0, 0, NULL, '2026-04-06 11:57:00', '2026-04-06 13:13:05', 0, NULL),
(196, 2, 0, 'PN260400004', '00002', 'Tanah Putra Ariyadi', 'tanah-putra-ariyadi', 'Tanah', 'land', 4, 'DRAFT', '2026-10-06', 'PRPDT88', 'PROSPEDITY', 'prospedity@gmail.com', '+6281958888351', 0.00, NULL, NULL, NULL, NULL, NULL, 0, 0, 'Jl. Sidayu Tojan', 'Klungkung', -8.57244700, 115.38859210, NULL, NULL, '8m x 12m', 'South', NULL, NULL, 'Pantai', NULL, NULL, NULL, 'YELLOW', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 0, 0, 0, 0, NULL, NULL, NULL, 'Sumur Bor & PDAM', NULL, NULL, NULL, NULL, 0, 0, 0, 0, 0, 0, 0, 0, NULL, '2026-04-06 12:00:40', '2026-04-06 12:00:40', 0, NULL),
(197, 2, 3, 'PN260400005', '00002', 'TANAH PLOT KECIL FREEHOLD DI CEMAGI MENGENING BALI', 'tanah-merrie', 'Lokasi tenang dengan akses mudah, dekat pantai dan kawasan berkembang. Cocok untuk villa pribadi atau investasi dengan potensi kenaikan value yang menarik.', 'land', 4, 'AVAILABLE', '2026-10-03', 'PRPDT88', 'PROSPEDITY', 'prospedity@gmail.com', '+6281958888351', 700000000.00, NULL, NULL, 700000000.00, NULL, NULL, 0, 0, 'Jl. Umalalang', 'Cemagi', -8.63289200, 115.10337600, 223.00, NULL, '13,4m  x 14,97m', NULL, NULL, NULL, 'Sawah & laut', NULL, NULL, NULL, 'GREEN', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 0, 0, 0, 0, NULL, NULL, NULL, 'Sumur Bor', NULL, NULL, NULL, NULL, 0, 0, 0, 0, 0, 0, 0, 0, '± 750m dari Jalan Pantai Mengening Cemagi dan ± 1.5 km ke Pantai Mengening Cemagi\r\nBisa dapat view laut kalau bangun 2 lantai', '2026-04-06 12:04:09', '2026-04-08 05:01:39', 0, NULL),
(200, 2, 3, 'PN260400006', '00001', 'NEW VILLA WITH HIGH QUALITY MATERIALS - CENTRAL UNGASAN', 'new-villa-with-high-quality-materials-central-ungasan', 'We are offering a 3-bedroom villa for sale in the central area of ​​Ungasan, in a very convenient location: Uluwatu is just 15 minutes away, Melasti Beach is 5 minutes by bike, and beaches, restaurants, as well as a shopping mall with a cinema, are all nearby. \r\n\r\nThe villa is finished with high-quality decorative plaster and decorative coating, premium furniture and kitchen set, and offers a wide variety of lighting scenarios throughout the villa. The leasehold is for 24 years with priority extension rights. All final documents, including the SLF, have already been obtained.\r\nNeighboring villas in the same complex are already generating a solid 12% annual return on invested capital.', 'villas', 1, 'AVAILABLE', '2027-04-08', 'PPB12MAE', 'Mellyta', 'balimellytaa@gmail.com', '+62 812-3774-1674', 6000000000.00, NULL, NULL, NULL, 6000000000.00, 29, 0, 0, 'Jl Toya Ning II', 'Ungasan', -8.82528780, 115.14578760, 470.00, 167.00, '20m x 11m', 'East', 2026, 1, NULL, 'Modern Minimalist', NULL, 'Ada', 'YELLOW', 'Open-Closed', 'Open-Closed', 'Open-Closed', 3, 1, 3, NULL, '1', 1, 0, 0, 0, 'Fully Furnished', '7700', NULL, 'PDAM', NULL, 'Private', '1 car + 2 motorcycle', NULL, 0, 0, 0, 0, 0, 0, 0, 0, NULL, '2026-04-08 04:39:58', '2026-04-08 04:41:56', 0, NULL);
